#!/usr/bin/env node
/*
 * Re-apply Android release shrinking/obfuscation (R8) after `expo prebuild`.
 *
 * `android/` is CNG (regenerated by prebuild) and ships with minify OFF, so this
 * re-enables R8 + resource shrinking in android/gradle.properties and re-adds the
 * RN/Hermes/Expo keep rules to android/app/proguard-rules.pro. Idempotent — runs
 * from `postinstall` (no-ops when android/ is absent or already patched).
 *
 * Run manually after a prebuild:  node scripts/patch-android-minify.js
 */
const fs = require('fs');
const path = require('path');

const androidDir = path.join(__dirname, '..', 'android');
if (!fs.existsSync(androidDir)) process.exit(0); // managed / not prebuilt yet

// 1) gradle.properties — enable R8 + resource shrinking.
const gp = path.join(androidDir, 'gradle.properties');
if (fs.existsSync(gp)) {
  let s = fs.readFileSync(gp, 'utf8');
  if (!s.includes('android.enableMinifyInReleaseBuilds')) {
    s = s.trimEnd() + '\n\n' +
      '# Release shrinking + obfuscation (R8) and unused-resource removal.\n' +
      'android.enableMinifyInReleaseBuilds=true\n' +
      'android.enableShrinkResourcesInReleaseBuilds=true\n';
    fs.writeFileSync(gp, s);
    console.log('[patch-android-minify] enabled R8 + resource shrinking in gradle.properties');
  }
}

// 2) proguard-rules.pro — append the RN/Hermes/Expo safety-net keep rules.
const pg = path.join(androidDir, 'app', 'proguard-rules.pro');
const MARKER = 'Marine Safety Manager — release shrink/obfuscation safety net';
const RULES = `
# ===================================================================
# Marine Safety Manager — release shrink/obfuscation safety net (R8).
# (App logic is JS -> Hermes bytecode and is unaffected by R8.)
# ===================================================================
-keep,includedescriptorclasses class com.facebook.react.bridge.** { *; }
-keep,includedescriptorclasses class com.facebook.react.uimanager.** { *; }
-keep class com.facebook.jni.** { *; }
-keep class com.facebook.hermes.** { *; }
-dontwarn com.facebook.react.**
-dontwarn com.facebook.hermes.**
-keepclassmembers class * { @com.facebook.react.bridge.ReactMethod <methods>; }
-keepclassmembers,allowobfuscation class * {
    @com.facebook.proguard.annotations.DoNotStrip *;
    @com.facebook.common.internal.DoNotStrip *;
}
-keep class expo.modules.** { *; }
-dontwarn expo.modules.**
-dontwarn okhttp3.**
-dontwarn okio.**
`;
if (fs.existsSync(pg)) {
  const s = fs.readFileSync(pg, 'utf8');
  if (!s.includes(MARKER)) {
    fs.writeFileSync(pg, s.trimEnd() + '\n' + RULES);
    console.log('[patch-android-minify] added keep rules to proguard-rules.pro');
  }
}
